// personal-appointment.service.ts
import { Injectable } from '@angular/core';
import { BaseService } from './Base/base.service';
import { PersonalAppointment } from '../models';

@Injectable({ providedIn: 'root' })
export class PersonalAppointmentService extends BaseService<PersonalAppointment> {
  protected override getTableName(): string {
    return 'personal_appointments';
  }

  // Metodi specifici se necessari (es. loadByDateRange)
  async loadByDateRange(start: Date, end: Date): Promise<PersonalAppointment[]> {
    const restaurantId = await this.getCurrentRestaurantId();
    if (!restaurantId) return [];

    const { data, error } = await this.getSupabaseClientPublic()
      .from(this.getTableName())
      .select('*')
      .eq('restaurant_id', restaurantId)
      .gte('start_datetime', start.toISOString())
      .lte('end_datetime', end.toISOString())
      .order('start_datetime', { ascending: true });

    if (error) {
      this.handleError('loadByDateRange', error);
      return [];
    }
    return data || [];
  }
}